import asyncio
from functools import wraps

def with_retry(max_attempts=3, delay_seconds=5, backoff=2.0):
    def decorator(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            attempt = 0
            current_delay = delay_seconds
            while attempt < max_attempts:
                try:
                    return await func(*args, **kwargs)
                except TimeoutError as e:
                    attempt += 1
                    if attempt >= max_attempts:
                        raise
                    print(f"Selector timeout, retrying in {current_delay}s ({attempt}/{max_attempts})")
                    await asyncio.sleep(current_delay)
                    current_delay *= backoff
                except SessionExpiredError:
                    # Non-retryable — re-authenticate first
                    raise
                except RateLimitError as e:
                    # Wait for platform's specified cooldown
                    await asyncio.sleep(e.retry_after)
                    attempt += 1
        return wrapper
    return decorator

@with_retry(max_attempts=3, delay_seconds=10)
async def post_with_retry(adapter, page, content):
    return await adapter.post(page, content)
